import pandas as pd


class Indexer:
    def __init__(self, idx_col='user_id'):
        self.idx_col = idx_col

    def prepare(self, df):
        # sets idx_col as index, removing it from columns
        return df.set_index(self.idx_col)

    def query(self, df):
        # BUG: user_id is now the index, not a column
        return df[df['user_id'] > 100]


def query(df):
    i = Indexer()
    df2 = i.prepare(df)
    return i.query(df2)


def main():
    df = pd.DataFrame({'user_id': [50, 150, 250], 'name': ['a', 'b', 'c']})
    filtered = query(df)
    print(filtered)


if __name__ == '__main__':
    main()
